import{_ as t,o as r,c as s,ag as e}from"./chunks/framework.ETe_P6d1.js";const p="/kaiping-reports/assets/1.Dgx8l7Zx.jpg",o="/kaiping-reports/assets/2.RCQKhOKb.jpg",i="/kaiping-reports/assets/3.BZBu69Lt.jpg",n="/kaiping-reports/assets/4.B-lJIOMi.jpg",_="/kaiping-reports/assets/5.BnheuCaM.jpg",l="/kaiping-reports/assets/6.tdaU1muG.jpg",h="/kaiping-reports/assets/7.BI_hrt4N.jpg",c="/kaiping-reports/assets/8.BJqLh7vA.jpg",d="/kaiping-reports/assets/9.DIN4U1BT.jpg",m="/kaiping-reports/assets/10.BLQ8Z9QB.jpg",B=JSON.parse('{"title":"活态保育与文旅重塑:仓东村与赤坎古镇侨乡建筑遗产保护对比观察报告","description":"","frontmatter":{},"headers":[],"relativePath":"reports/李杏/李杏_关于仓东村和赤坎古镇的调研报告.md","filePath":"reports/李杏/李杏_关于仓东村和赤坎古镇的调研报告.md"}'),u={name:"reports/李杏/李杏_关于仓东村和赤坎古镇的调研报告.md"};function g(q,a,k,b,f,x){return r(),s("div",null,[...a[0]||(a[0]=[e('<h1 id="活态保育与文旅重塑-仓东村与赤坎古镇侨乡建筑遗产保护对比观察报告" tabindex="-1">活态保育与文旅重塑:仓东村与赤坎古镇侨乡建筑遗产保护对比观察报告 <a class="header-anchor" href="#活态保育与文旅重塑-仓东村与赤坎古镇侨乡建筑遗产保护对比观察报告" aria-label="Permalink to &quot;活态保育与文旅重塑:仓东村与赤坎古镇侨乡建筑遗产保护对比观察报告&quot;">​</a></h1><p><strong>作者：李杏</strong></p><p>引言 开平侨乡建筑是近代华侨文化、岭南乡土营造与西方建筑技术相互融合的特殊产物，兼具居住、防御、商贸、礼制等多重价值。本次观察选取仓东村与赤坎古镇作为对比案例，前者代表乡土宗族村落，后者代表近代商业骑楼街区，二者呈现出完全不同的遗产特征与保护路径。报告围绕适应性改造与场所精神延续两大专业主题，从空间形态、材料构造、装饰文化、功能转化、现代利用等维度展开对比分析，结合建筑遗产保护的原真性、最小干预、活态传承理论，对两种保护模式进行批判性反思，最终提炼侨乡遗产保护的核心启示。</p><h2 id="一、空间类型与形态-村落肌理与骑楼街区的差异" tabindex="-1">一、空间类型与形态:村落肌理与骑楼街区的差异 <a class="header-anchor" href="#一、空间类型与形态-村落肌理与骑楼街区的差异" aria-label="Permalink to &quot;一、空间类型与形态:村落肌理与骑楼街区的差异&quot;">​</a></h2><p>仓东村是典型的岭南宗族村落，建筑以民居、祠堂、碉楼为主，布局为梳式联排形态，空间序列由村口巷道、公共晒场、祠堂、民居院落组成，呈现内向、礼制化、层级清晰的特征。建筑顺应农田平缓地形自然生长，街巷曲折尺度亲切，整体肌理有机、原生、紧凑。仓东的空间逻辑以宗族生活为中心，强调私密性与归属感。</p><p>赤坎古镇则为沿江商业骑楼街区，以连续骑楼商铺构成主体，建筑沿街线性排布，形成强烈的公共商业界面。空间序列为江面-街道-骑楼廊道-商铺一内宅，外向、开放、流线清晰。骑楼廊道作为岭南气候适应性空间，承担遮阳、避雨、商业展示等功能，使整条街道形成连续、统一、富有节奏感的公共步行系统。赤坎的空间逻辑以商贸活动为中心，强调公共性与开放性。</p><p>从环境关系看，仓东村嵌入田园，视野内敛，氛围宁静;赤坎临江而建，视线开阔，具有强烈的城镇商业气质。二者空间基底的差异，决定了后续保护模式、改造强度与功能方向的根本不同。</p><p><img src="'+p+'" alt="图1"><img src="'+o+'" alt="图2"></p><h2 id="二、建造材料与构造-乡土传统工艺与近代混合结构" tabindex="-1">二、建造材料与构造:乡土传统工艺与近代混合结构 <a class="header-anchor" href="#二、建造材料与构造-乡土传统工艺与近代混合结构" aria-label="Permalink to &quot;二、建造材料与构造:乡土传统工艺与近代混合结构&quot;">​</a></h2><p>仓东村以砖木结构、夯土、青砖墙为主要构造体系，木构架承重，墙体围护，屋面为小青瓦铺设，构造节点以榫卯与传统手工砌筑为主。建筑材料全部来自本地，施工痕迹朴素自然，几乎无现代工业材料，呈现最本真的岭南乡土营造技艺。</p><p>赤坎古镇骑楼则采用近代混合结构，以砖混、砖木、局部钢筋混凝土为主。骑楼廊道依靠混凝土悬挑或木挑梁实现，立面材料包括红砖、抹灰、仿石饰面，构造方式融合砌筑、现浇、简易预制等技术，结构更坚固、防火性更强、空间适应性更高，是西方技术传入岭南后的本土化成果。</p><p>从构造逻辑看，仓东代表传统乡村营造，追求实用、耐久、低调;赤坎代表近代城镇商业建造，追求形式、稳定、形象展示。两种构造体系共同构成侨乡建筑从传统走向近代的技术脉络。</p><p><img src="'+i+'" alt="图3"><img src="'+n+'" alt="图4"></p><h2 id="三、装饰符号与文化表达-内敛乡土与成熟中西合璧" tabindex="-1">三、装饰符号与文化表达:内敛乡土与成熟中西合璧 <a class="header-anchor" href="#三、装饰符号与文化表达-内敛乡土与成熟中西合璧" aria-label="Permalink to &quot;三、装饰符号与文化表达:内敛乡土与成熟中西合璧&quot;">​</a></h2><p>仓东村装饰简约、朴素、以中式为主，仅少量窗楣出现简化西式线条。装饰集中在祠堂门楣、檐下、屋脊，题材以吉祥纹样、植物纹、文字为主，色彩以青砖灰、木色、灰塑本色为主，整体风格内敛克制，反映归侨重视宗族、回归乡土的文化心态。</p><p>赤坎古镇骑楼则是侨乡中西合璧风格最成熟的代表。立面大量采用西式三段式构图、壁柱、拱券、山花、线脚，同时保留岭南骑楼敞廊、大窗、商业界面等本土特征。装饰题材混合西式纹样、中式灰塑、商号文字，视觉效果鲜明、商业气息浓厚，是华侨开放文化与商业展示需求的物质体现。</p><p><img src="'+_+'" alt="图5"><img src="'+l+'" alt="图6"></p><h2 id="四、功能布局与适应性改造-两种保护路径的对比" tabindex="-1">四、功能布局与适应性改造:两种保护路径的对比 <a class="header-anchor" href="#四、功能布局与适应性改造-两种保护路径的对比" aria-label="Permalink to &quot;四、功能布局与适应性改造:两种保护路径的对比&quot;">​</a></h2><p>仓东村原始功能为宗族聚居、祭祀、防御、农耕生活。现代改造采用微更新、最小干预、活态社区保育模式，仅对建筑进行结构加固与局部修复，内部隐蔽植入现代厨卫、照明等设施，外观与空间格局完全保留。功能转化为遗产教育、研学、社区公共空间，并继续保留原住民居住，使村落维持真实生活场景，实现建筑与生活的共同延续。关起门来收门票并不是仓东村的目的，打造&quot;记录侨乡发展历史的天然博物馆&quot;才是仓东计划的真正目标。不过，仓东计划发起人谭金花更倾向于将苍东村打造成一个文化遗产教育基地，帮助更多海内外学生、学者乃至广大社会群体体验独具仓东村特色的生活氛围;通过开展特色文化活动、丰富与外地游客交流互动的形式等，传播文化遗产保护理念。[1]</p><p>赤坎古镇原始功能为前店后宅、商住复合，承担商贸、交易、社交、居住等功能。现代改造采用整体修缮、风貌复原、全域文旅开发模式，建筑结构加固、立面统一修复、街巷环境全面提升，功能整体转向文旅商业、民宿、餐饮、观光体验。原住民大量外迁，原生市井生活消失，街区从生活场所转变为文旅消费场景。</p><p>从改造强度看，仓东是轻介入、保生活、保原真;赤坎是大修复、重风貌、强商业。两种模式代表了当前侨乡遗产最典型的两种方向。从两地的祠堂功能便能看出这两种模式，仓东村的祠堂还是祭祀用，里面摆放着排位。而赤坎古镇的司徒公祠已经改造为文创小店。</p><p><img src="'+h+'" alt="图7"><img src="'+c+'" alt="图8"></p><h2 id="五、问题、反思与批判性思考" tabindex="-1">五、问题、反思与批判性思考 <a class="header-anchor" href="#五、问题、反思与批判性思考" aria-label="Permalink to &quot;五、问题、反思与批判性思考&quot;">​</a></h2><p>仓东村的问题主要为部分木构件老化、墙体风化、设施条件有限，但整体结构完好、风貌真实，未来仍可通过微更新持续保护。其保护模式符合活态遗产、社区参与、原真性保护理念，是乡村遗产最理想的路径之一。</p><p>赤坎古镇通过大规模改造有效拯救了濒危骑楼，修复历史风貌，提升环境品质，实现经济活化。但也带来商业同质化、生活性丧失、原真性细节弱化、场所精神淡化等问题。2015年，赤坎古镇管委会成立了征收管理办公室，负责房屋征收。然而，由于赤坎古镇旅游项目采取产权&quot;统一归属，整体开发&quot;的&quot;乌镇模式&quot;，赤坎古镇旅游项目面临近4000户房屋的征迁问题。[2]街区处处透露出历史生活气息，却不见曾经生活在这里的人。文旅开发追求统一、整洁、高效，而历史街区的价值恰恰在于多元、真实、日常的生活痕迹。</p><p>从建筑遗产保护理论来看，仓东模式守住了原真性与生活性，赤坎模式实现了风貌抢救与经济再生，二者各有价值，也各有取舍。</p><h2 id="六、结论" tabindex="-1">六、结论 <a class="header-anchor" href="#六、结论" aria-label="Permalink to &quot;六、结论&quot;">​</a></h2><p>仓东村与赤坎古镇的对比，展现了侨乡建筑遗产乡土村落活态保育与城镇街区文旅开发两种典型路径。仓东以微更新、保生活、轻商业的方式，完整保留建筑原真性、空间肌理与场所精神，成为乡土遗产保护的优秀范本;赤坎以整体修复、风貌重塑、功能置换的方式，挽救了濒危骑楼街区，但在商业化过程中削弱了生活真实性与历史独特性。</p><p>侨乡建筑的核心价值不仅在于中西合璧的外观，更在于空间类型、营造技艺、功能逻辑、人居文化、历史记忆的综合统一。真正可持续的保护，应坚持最小干预、可识别性、可逆性、活态使用原则:乡村遗产以保生活、保原住民、保原真为主;城镇商业遗产在文旅利用中应控制商业强度、保留历史细节、适度恢复生活功能。唯有让建筑继续被使用、让空间保持活力、让文化记忆不中断，侨乡遗产才能真正成为&quot;活着的遗产&quot;，在当代社会中持续传递华侨文化的历史厚度与精神价值。</p><h2 id="七、附录-调研记录" tabindex="-1">七、附录:调研记录 <a class="header-anchor" href="#七、附录-调研记录" aria-label="Permalink to &quot;七、附录:调研记录&quot;">​</a></h2><h3 id="_7-1摄影记录" tabindex="-1">7.1摄影记录 <a class="header-anchor" href="#_7-1摄影记录" aria-label="Permalink to &quot;7.1摄影记录&quot;">​</a></h3><p>本报告共插入10张现场照片，分别展示: 图1-图2:仓东村夫人庙、赤坎古镇商业骑楼 图3-图4:仓东村民居建造材料与构造展示、赤坎古镇建造材料与构造展示 图5-图6:仓东村祠堂装饰、赤坎古镇街景装饰 图7-图8:仓东村祠堂功能展示、赤坎古镇祠堂功能展示 图9-图10:仓东村民居内部展示、赤坎古镇商业性建筑内部展示</p><p><img src="'+d+'" alt="图9"><img src="'+m+'" alt="图10"></p><h3 id="_7-2文献资料" tabindex="-1">7.2文献资料 <a class="header-anchor" href="#_7-2文献资料" aria-label="Permalink to &quot;7.2文献资料&quot;">​</a></h3><p>[1]林巧欣.文化景观视角下开平碉楼与村落的保护和发展研究一一以仓东村为例[J].房地产世界,2023,(19):18-21. [2]张子昂,保继刚,贾文通.侨产资源对侨乡旅游地开发的尺度性影响过程与作用机制---以开平赤坎古镇为例[J].自然资源学报,2023,38(12):3058-3073.</p>',35)])])}const j=t(u,[["render",g]]);export{B as __pageData,j as default};
